using System.Security.Claims;using Microsoft.AspNetCore.Authorization;using Microsoft.AspNetCore.Mvc;using Microsoft.AspNetCore.Mvc.RazorPages;using Microsoft.EntityFrameworkCore;using ProjectManagement.Features.MediaLibrary.Data;using ProjectManagement.Features.MediaLibrary.Domain;using ProjectManagement.Features.MediaLibrary.Services;
namespace ProjectManagement.Pages.Photos.People;[Authorize(Roles="Admin,HoD")] public sealed class ReviewModel:PageModel{private readonly MediaLibraryDbContext _db;private readonly IFaceReviewService _review;public ReviewModel(MediaLibraryDbContext db,IFaceReviewService review){_db=db;_review=review;}public IReadOnlyList<Row> Items{get;private set;}=[];public async Task OnGetAsync(CancellationToken ct){Items=await _db.FaceReviewDecisions.AsNoTracking().Where(x=>x.Decision==FaceReviewDecisionType.Pending).OrderByDescending(x=>x.Similarity).Take(100).Select(x=>new Row(x.Id,x.MediaFaceId,x.CandidatePersonId,x.CandidatePerson!=null?x.CandidatePerson.DisplayName:null,x.Similarity,x.MediaFace.MediaAsset.ContextTitle)).ToListAsync(ct);}public async Task<IActionResult> OnPostConfirmAsync(Guid faceId,Guid personId,double? confidence,CancellationToken ct){await _review.AssignAsync(faceId,personId,User.FindFirstValue(ClaimTypes.NameIdentifier)??"unknown",confidence,ct);return RedirectToPage();}public async Task<IActionResult> OnPostRejectAsync(Guid faceId,Guid? personId,CancellationToken ct){await _review.RejectAsync(faceId,personId,User.FindFirstValue(ClaimTypes.NameIdentifier)??"unknown",ct);return RedirectToPage();}public async Task<IActionResult> OnPostCreateAsync(Guid faceId,string displayName,CancellationToken ct){if(!string.IsNullOrWhiteSpace(displayName))await _review.CreatePersonAndAssignAsync(faceId,displayName,User.FindFirstValue(ClaimTypes.NameIdentifier)??"unknown",ct);return RedirectToPage();}public sealed record Row(long Id,Guid FaceId,Guid? PersonId,string? PersonName,double? Similarity,string ContextTitle);}
